{
  "name": "StroyExpress Architect & Marketplace Prototype",
  "description": "A comprehensive functional specification and interactive prototype for a construction marketplace in Uzbekistan, featuring dual pricing, multilingual support, and a detailed database schema viewer."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Language = 'ru' | 'uz';

export enum OrderStatus {
  PENDING = 'PENDING',
  PROCESSING = 'PROCESSING',
  DELIVERING = 'DELIVERING',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export interface Product {
  id: string;
  name: {
    ru: string;
    uz: string;
  };
  category: string;
  description: {
    ru: string;
    uz: string;
  };
  priceRetail: number;
  priceWholesale: number;
  wholesaleMinQty: number;
  image: string;
  sellerId: string;
  rating: number;
}

export interface CartItem extends Product {
  quantity: number;
  isWholesale: boolean;
}

export interface User {
  id: string;
  phone: string;
  name: string;
  referralCode: string;
  referredBy?: string;
  balance: number;
  language: Language;
}

export interface SchemaTable {
  name: string;
  description: string;
  columns: {
    name: string;
    type: string;
    key?: 'PK' | 'FK';
    description: string;
  }[];
}

import React, { useState } from 'react';
import { Language, Product, CartItem } from '../types';
import { TRANSLATIONS, MOCK_PRODUCTS } from '../constants';
import { ShoppingCart, Search, User, Home, Heart, MessageCircle, ChevronRight, Check } from 'lucide-react';

interface Props {
  lang: Language;
}

const MarketplaceView: React.FC<Props> = ({ lang }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [view, setView] = useState<'home' | 'cart' | 'profile'>('home');
  const [search, setSearch] = useState('');
  const t = TRANSLATIONS[lang];

  const addToCart = (product: Product, isWholesale: boolean) => {
    const existing = cart.find(item => item.id === product.id && item.isWholesale === isWholesale);
    if (existing) {
      setCart(cart.map(item => 
        (item.id === product.id && item.isWholesale === isWholesale) 
          ? { ...item, quantity: item.quantity + 1 } 
          : item
      ));
    } else {
      setCart([...cart, { ...product, quantity: isWholesale ? product.wholesaleMinQty : 1, isWholesale }]);
    }
  };

  const total = cart.reduce((acc, item) => 
    acc + (item.isWholesale ? item.priceWholesale : item.priceRetail) * item.quantity, 0
  );

  return (
    <div className="flex flex-col h-full max-w-md mx-auto bg-gray-50 relative border-x border-gray-200 min-h-[90vh] shadow-xl">
      {/* Header */}
      <header className="bg-yellow-400 p-4 sticky top-0 z-10 shadow-md">
        <div className="flex items-center justify-between mb-4">
          <h1 className="text-xl font-black italic tracking-tighter text-black uppercase">{t.appTitle}</h1>
          <div className="flex gap-3">
            <button className="bg-white/50 p-1.5 rounded-full"><MessageCircle size={18} /></button>
            <button className="bg-white/50 p-1.5 rounded-full relative">
              <ShoppingCart size={18} onClick={() => setView('cart')} />
              {cart.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center font-bold">{cart.length}</span>}
            </button>
          </div>
        </div>
        <div className="relative">
          <input 
            type="text" 
            placeholder={t.searchPlaceholder}
            className="w-full pl-10 pr-4 py-2 rounded-lg bg-white border-none focus:ring-2 focus:ring-black/10 text-sm"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <Search className="absolute left-3 top-2.5 text-gray-400" size={16} />
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 p-4 pb-24 overflow-y-auto">
        {view === 'home' && (
          <div className="space-y-6">
            {/* Promo Banner */}
            <div className="bg-black text-white p-4 rounded-2xl relative overflow-hidden">
              <div className="relative z-10">
                <p className="text-yellow-400 font-bold text-xs mb-1">FREE DELIVERY</p>
                <h3 className="text-lg font-bold leading-tight">Order above 5m UZS<br/>& Get Free Truck!</h3>
              </div>
              <div className="absolute top-0 right-0 w-24 h-full bg-yellow-400/20 skew-x-12 -mr-8"></div>
            </div>

            {/* Categories */}
            <div>
              <div className="flex justify-between items-center mb-3">
                <h2 className="font-bold">{t.categories}</h2>
                <button className="text-xs text-blue-600 font-medium">All</button>
              </div>
              <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
                {['Cement', 'Steel', 'Tools', 'Brick', 'Sand'].map(c => (
                  <div key={c} className="flex-shrink-0 px-4 py-2 bg-white rounded-xl border border-gray-100 text-sm font-medium shadow-sm">
                    {c}
                  </div>
                ))}
              </div>
            </div>

            {/* Products Grid */}
            <div className="grid grid-cols-2 gap-3">
              {MOCK_PRODUCTS.filter(p => p.name[lang].toLowerCase().includes(search.toLowerCase())).map(product => (
                <div key={product.id} className="bg-white rounded-2xl overflow-hidden border border-gray-100 shadow-sm flex flex-col">
                  <div className="relative aspect-square">
                    <img src={product.image} alt={product.name[lang]} className="w-full h-full object-cover" />
                    <button className="absolute top-2 right-2 bg-white/80 p-1.5 rounded-full"><Heart size={14} /></button>
                    {product.rating > 4.7 && <div className="absolute bottom-2 left-2 bg-yellow-400 px-2 py-0.5 rounded text-[10px] font-bold">BEST SELLER</div>}
                  </div>
                  <div className="p-3 flex-1 flex flex-col">
                    <h3 className="text-sm font-bold line-clamp-2 mb-1">{product.name[lang]}</h3>

                    {/* Retail Pricing */}
                    <div className="mt-auto pt-2 border-t border-gray-50">
                      <div className="flex justify-between items-baseline mb-2">
                        <span className="text-[10px] text-gray-500">{t.retail}</span>
                        <span className="text-sm font-bold text-gray-900">{product.priceRetail.toLocaleString()} <span className="text-[10px] font-normal">UZS</span></span>
                      </div>
                      <button 
                        onClick={() => addToCart(product, false)}
                        className="w-full py-1.5 bg-gray-100 hover:bg-gray-200 transition-colors rounded-lg text-xs font-bold mb-3"
                      >
                        + {t.addToCart}
                      </button>

                      {/* Wholesale Pricing */}
                      <div className="bg-yellow-50 p-2 rounded-lg border border-yellow-100">
                        <div className="flex justify-between items-baseline mb-1">
                          <span className="text-[10px] text-yellow-700 font-bold uppercase">{t.wholesale}</span>
                          <span className="text-sm font-bold text-yellow-900">{product.priceWholesale.toLocaleString()} <span className="text-[10px] font-normal">UZS</span></span>
                        </div>
                        <p className="text-[9px] text-yellow-600 mb-2 italic">{t.minQty} {product.wholesaleMinQty}</p>
                        <button 
                          onClick={() => addToCart(product, true)}
                          className="w-full py-1.5 bg-yellow-400 hover:bg-yellow-500 transition-colors rounded-lg text-xs font-bold text-black"
                        >
                          + {t.addToCart}
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {view === 'cart' && (
          <div className="space-y-4">
            <div className="flex items-center gap-2 mb-4">
              <button onClick={() => setView('home')} className="p-1 hover:bg-gray-100 rounded-full"><ChevronRight className="rotate-180" size={20} /></button>
              <h2 className="text-lg font-bold">Shopping Cart</h2>
            </div>
            {cart.length === 0 ? (
              <div className="text-center py-12 text-gray-400">Your cart is empty</div>
            ) : (
              <>
                {cart.map((item, idx) => (
                  <div key={`${item.id}-${idx}`} className="flex gap-4 bg-white p-3 rounded-xl border border-gray-100 shadow-sm">
                    <img src={item.image} className="w-20 h-20 rounded-lg object-cover" />
                    <div className="flex-1">
                      <div className="flex justify-between">
                        <h4 className="font-bold text-sm">{item.name[lang]}</h4>
                        {item.isWholesale && <span className="bg-yellow-100 text-yellow-800 text-[10px] px-1.5 py-0.5 rounded h-fit font-bold uppercase">Wholesale</span>}
                      </div>
                      <div className="mt-1 text-sm font-bold">
                        {(item.isWholesale ? item.priceWholesale : item.priceRetail).toLocaleString()} UZS
                      </div>
                      <div className="mt-2 flex items-center gap-3">
                        <span className="text-xs text-gray-500">Qty: {item.quantity}</span>
                        <button className="text-xs text-red-500 font-medium" onClick={() => setCart(cart.filter((_, i) => i !== idx))}>Remove</button>
                      </div>
                    </div>
                  </div>
                ))}

                <div className="bg-white p-4 rounded-xl border border-gray-100 space-y-3 shadow-sm mt-6">
                  <div className="flex justify-between items-center text-sm">
                    <span className="text-gray-500">{t.loaderService}</span>
                    <input type="checkbox" className="w-5 h-5 rounded border-gray-300 text-yellow-500 focus:ring-yellow-500" />
                  </div>
                  <div className="pt-3 border-t border-gray-100 flex justify-between items-center font-bold">
                    <span>{t.total}</span>
                    <span className="text-lg">{total.toLocaleString()} UZS</span>
                  </div>
                  <button className="w-full py-3 bg-black text-white rounded-xl font-bold mt-2 shadow-lg hover:bg-gray-800 transition-all">
                    {t.checkout}
                  </button>
                </div>
              </>
            )}
          </div>
        )}

        {view === 'profile' && (
          <div className="space-y-6">
            <div className="flex items-center gap-4 bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
              <div className="w-16 h-16 bg-yellow-400 rounded-full flex items-center justify-center text-2xl font-bold">AK</div>
              <div>
                <h3 className="font-bold text-lg">Alisher Karimov</h3>
                <p className="text-sm text-gray-500">+998 90 123 45 67</p>
              </div>
            </div>

            <div className="bg-white rounded-2xl border border-gray-100 overflow-hidden shadow-sm">
              {[
                { icon: Home, label: t.history },
                { icon: Heart, label: t.favorites },
                { icon: User, label: t.referral },
                { icon: MessageCircle, label: t.support },
              ].map((item, i) => (
                <button key={i} className="w-full flex items-center justify-between p-4 hover:bg-gray-50 border-b border-gray-50 last:border-none">
                  <div className="flex items-center gap-3">
                    <item.icon size={18} className="text-gray-400" />
                    <span className="font-medium text-sm">{item.label}</span>
                  </div>
                  <ChevronRight size={16} className="text-gray-300" />
                </button>
              ))}
            </div>

            <div className="bg-blue-600 rounded-2xl p-4 text-white flex items-center justify-between shadow-lg">
              <div>
                <p className="text-[10px] uppercase font-bold text-blue-200">Refer & Earn</p>
                <h4 className="font-bold text-lg">INVITE-50</h4>
              </div>
              <button className="bg-white text-blue-600 px-4 py-2 rounded-xl text-xs font-bold shadow-md hover:bg-blue-50">Share</button>
            </div>
          </div>
        )}
      </main>

      {/* Navigation Bar */}
      <nav className="fixed bottom-4 left-1/2 -translate-x-1/2 w-[90%] max-w-[360px] bg-white/90 backdrop-blur-md rounded-2xl p-2 flex justify-around shadow-2xl border border-white/50 z-20">
        <button onClick={() => setView('home')} className={`p-3 rounded-xl transition-all ${view === 'home' ? 'bg-yellow-400 text-black shadow-inner' : 'text-gray-400 hover:text-gray-600'}`}>
          <Home size={22} />
        </button>
        <button onClick={() => setView('cart')} className={`p-3 rounded-xl transition-all ${view === 'cart' ? 'bg-yellow-400 text-black shadow-inner' : 'text-gray-400 hover:text-gray-600'}`}>
          <ShoppingCart size={22} />
        </button>
        <button onClick={() => setView('profile')} className={`p-3 rounded-xl transition-all ${view === 'profile' ? 'bg-yellow-400 text-black shadow-inner' : 'text-gray-400 hover:text-gray-600'}`}>
          <User size={22} />
        </button>
      </nav>
    </div>
  );
};

export default MarketplaceView;

import React, { useState } from 'react';
import { Language } from './types';
import { TRANSLATIONS } from './constants';
import MarketplaceView from './components/MarketplaceView';
import ArchitectView from './components/ArchitectView';
import { Layout, AppWindow, Database, Globe } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('ru');
  const [mode, setMode] = useState<'app' | 'architect'>('app');
  const t = TRANSLATIONS[lang];

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Top Global Control Bar */}
      <nav className="bg-white border-b border-gray-200 px-6 py-3 sticky top-0 z-50 shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2">
            <Layout className="text-yellow-500" />
            <span className="font-bold text-lg hidden sm:block">StroyExpress Architect</span>
          </div>

          <div className="flex bg-gray-100 p-1 rounded-lg">
            <button 
              onClick={() => setMode('app')}
              className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all ${mode === 'app' ? 'bg-white shadow text-black' : 'text-gray-500 hover:text-gray-700'}`}
            >
              <AppWindow size={16} />
              {t.appMode}
            </button>
            <button 
              onClick={() => setMode('architect')}
              className={`flex items-center gap-2 px-4 py-1.5 rounded-md text-sm font-medium transition-all ${mode === 'architect' ? 'bg-white shadow text-black' : 'text-gray-500 hover:text-gray-700'}`}
            >
              <Database size={16} />
              {t.schemaMode}
            </button>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <Globe size={18} className="text-gray-400" />
          <div className="flex border rounded-lg overflow-hidden text-xs font-bold">
            <button 
              onClick={() => setLang('ru')}
              className={`px-3 py-1.5 ${lang === 'ru' ? 'bg-gray-900 text-white' : 'bg-white text-gray-700 hover:bg-gray-50'}`}
            >
              RU
            </button>
            <button 
              onClick={() => setLang('uz')}
              className={`px-3 py-1.5 ${lang === 'uz' ? 'bg-gray-900 text-white' : 'bg-white text-gray-700 hover:bg-gray-50'}`}
            >
              UZ
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1">
        {mode === 'app' ? (
          <div className="py-8 px-4">
             <div className="mb-8 text-center max-w-lg mx-auto">
                <h2 className="text-2xl font-bold text-gray-800 mb-2">Interactive Prototype</h2>
                <p className="text-gray-500 text-sm">Experience the user interface and logic for dual-pricing, multi-language switching, and localized construction marketplace features.</p>
             </div>
             <MarketplaceView lang={lang} />
          </div>
        ) : (
          <ArchitectView />
        )}
      </main>

      <footer className="bg-white border-t border-gray-200 py-6 text-center text-gray-400 text-xs">
        &copy; 2024 StroyExpress Systems Architecture. Developed for No-Code Systems Implementation.
      </footer>
    </div>
  );
};

export default App;

export type Language = 'ru' | 'uz';

export interface Attribute {
  key: string;
  label: { ru: string; uz: string };
  value: string;
  isPrimary: boolean;
}

export interface Review {
  id: string;
  userId: string;
  userName: string;
  rating: number;
  date: string;
  isVerified: boolean;
  pros: string;
  cons: string;
  comment: string;
  photos?: string[];
}

export interface Product {
  id: string;
  slug: string;
  name: { ru: string; uz: string };
  category: string;
  description: { ru: string; uz: string };
  priceRetail: number;
  priceWholesale: number;
  wholesaleMinQty: number;
  image: string;
  sellerId: string;
  rating: number;
  totalReviews: number;
  soldLastMonth: number;
  stock: number;
  attributes: Attribute[];
}

export interface CartItem extends Product {
  quantity: number;
  isWholesale: boolean;
}

export interface SchemaTable {
  name: string;
  description: string;
  columns: {
    name: string;
    type: string;
    key?: 'PK' | 'FK';
    description: string;
  }[];
}

import React, { useState } from 'react';
import { Product, Language, Review } from '../types';
import { TRANSLATIONS } from '../constants';
import { X, Star, CheckCircle, Package, TrendingUp, ChevronDown } from 'lucide-react';

interface Props {
  product: Product;
  lang: Language;
  onClose: () => void;
  onAddToCart: (p: Product, isWholesale: boolean) => void;
}

const ProductModal: React.FC<Props> = ({ product, lang, onClose, onAddToCart }) => {
  const [activeTab, setActiveTab] = useState<'specs' | 'reviews'>('specs');
  const [specFilter, setSpecFilter] = useState<'main' | 'all'>('main');
  const t = TRANSLATIONS[lang];

  // Имитация отзывов
  const mockReviews: Review[] = [
    {
      id: 'r1',
      userId: 'u1',
      userName: 'Дмитрий В.',
      rating: 5,
      date: '12.10.2023',
      isVerified: true,
      pros: 'Отличное качество, быстрая доставка.',
      cons: 'Не обнаружил.',
      comment: 'Брал для заливки фундамента, схватывается отлично.'
    },
    {
      id: 'r2',
      userId: 'u2',
      userName: 'Sardor M.',
      rating: 4,
      date: '05.10.2023',
      isVerified: true,
      pros: 'Yaxshi narx.',
      cons: 'Qadoqlash biroz yomon.',
      comment: 'Hammasi joyida, rahmat.'
    }
  ];

  const stockWarning = product.stock < 10;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white w-full max-w-2xl max-h-[90vh] rounded-3xl overflow-hidden flex flex-col shadow-2xl relative">
        {/* Close Button */}
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 z-10 p-2 bg-white/80 hover:bg-white rounded-full shadow-md transition-all"
        >
          <X size={20} />
        </button>

        <div className="overflow-y-auto flex-1">
          {/* Top Section: Media & Trust */}
          <div className="grid md:grid-cols-2 gap-0">
            <div className="relative aspect-square bg-gray-100">
              <img src={product.image} alt={product.name[lang]} className="w-full h-full object-cover" />
              {product.rating > 4.5 && (
                <div className="absolute top-4 left-4 bg-yellow-400 text-black px-3 py-1 rounded-full text-xs font-black shadow-lg">
                  TOP RATED
                </div>
              )}
            </div>

            <div className="p-6 flex flex-col justify-between">
              <div>
                <h2 className="text-2xl font-black leading-tight text-gray-900 mb-2">{product.name[lang]}</h2>

                {/* Trust Metrics */}
                <div className="flex items-center gap-4 mb-4">
                  <div className="flex items-center gap-1 text-yellow-500">
                    <Star size={16} fill="currentColor" />
                    <span className="font-bold text-black">{product.rating}</span>
                    <span className="text-gray-400 text-sm">({product.totalReviews})</span>
                  </div>
                  <div className="flex items-center gap-1 text-green-600 text-sm font-medium">
                    <TrendingUp size={16} />
                    <span>{product.soldLastMonth} {t.soldMonthly}</span>
                  </div>
                </div>

                {/* Stock Level */}
                <div className={`flex items-center gap-2 mb-6 text-sm font-bold p-3 rounded-xl ${stockWarning ? 'bg-red-50 text-red-600 animate-pulse' : 'bg-green-50 text-green-700'}`}>
                  <Package size={18} />
                  <span>{product.stock} {t.leftInStock}</span>
                </div>
              </div>

              {/* Price Block */}
              <div className="space-y-3">
                <div className="flex justify-between items-end">
                  <span className="text-xs text-gray-500 font-bold uppercase tracking-wider">{t.retail}</span>
                  <span className="text-2xl font-black text-gray-900">{product.priceRetail.toLocaleString()} UZS</span>
                </div>
                <div className="bg-yellow-400/10 border border-yellow-400/30 p-3 rounded-2xl flex justify-between items-center">
                  <div>
                    <span className="text-[10px] font-black text-yellow-700 uppercase block">{t.wholesale}</span>
                    <span className="text-sm font-bold text-gray-800 italic">{t.minQty} {product.wholesaleMinQty}</span>
                  </div>
                  <span className="text-xl font-black text-yellow-700">{product.priceWholesale.toLocaleString()} UZS</span>
                </div>
              </div>
            </div>
          </div>

          {/* Bottom Section: Tabs */}
          <div className="p-6">
            <div className="flex border-b border-gray-100 mb-6 gap-8">
              <button 
                onClick={() => setActiveTab('specs')}
                className={`pb-3 text-sm font-black transition-all border-b-2 ${activeTab === 'specs' ? 'border-black text-black' : 'border-transparent text-gray-400'}`}
              >
                {t.allSpecs.toUpperCase()}
              </button>
              <button 
                onClick={() => setActiveTab('reviews')}
                className={`pb-3 text-sm font-black transition-all border-b-2 ${activeTab === 'reviews' ? 'border-black text-black' : 'border-transparent text-gray-400'}`}
              >
                {t.reviews.toUpperCase()} ({product.totalReviews})
              </button>
            </div>

            {activeTab === 'specs' && (
              <div className="space-y-4">
                <div className="flex gap-2 mb-4">
                  <button 
                    onClick={() => setSpecFilter('main')}
                    className={`px-4 py-1.5 rounded-full text-xs font-bold transition-all ${specFilter === 'main' ? 'bg-black text-white' : 'bg-gray-100 text-gray-500'}`}
                  >
                    {t.mainSpecs}
                  </button>
                  <button 
                    onClick={() => setSpecFilter('all')}
                    className={`px-4 py-1.5 rounded-full text-xs font-bold transition-all ${specFilter === 'all' ? 'bg-black text-white' : 'bg-gray-100 text-gray-500'}`}
                  >
                    {t.allSpecs}
                  </button>
                </div>
                <div className="grid grid-cols-1 gap-1">
                  {product.attributes
                    .filter(a => specFilter === 'all' || a.isPrimary)
                    .map(attr => (
                      <div key={attr.key} className="flex justify-between py-3 border-b border-gray-50 text-sm">
                        <span className="text-gray-500 font-medium">{attr.label[lang]}</span>
                        <span className="text-black font-bold">{attr.value}</span>
                      </div>
                    ))
                  }
                </div>
                <div className="mt-6">
                   <p className="text-gray-600 text-sm leading-relaxed leading-7">{product.description[lang]}</p>
                </div>
              </div>
            )}

            {activeTab === 'reviews' && (
              <div className="space-y-6">
                {mockReviews.map(review => (
