import React, { useState, useEffect, useCallback } from 'react';
import { Language, Product, CartItem } from '../types';
import { TRANSLATIONS, MOCK_PRODUCTS } from '../constants';
import { ShoppingCart, Search, User, Home, Heart, MessageCircle, ChevronRight, Check, Star } from 'lucide-react';
import ProductModal from './ProductModal';

interface Props {
  lang: Language;
}

const MarketplaceView: React.FC<Props> = ({ lang }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [view, setView] = useState<'home' | 'cart' | 'profile'>('home');
  const [search, setSearch] = useState('');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const t = TRANSLATIONS[lang];

  // Deep Linking logic: check URL for product ID
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const prodId = params.get('product');
    if (prodId) {
      const prod = MOCK_PRODUCTS.find(p => p.id === prodId);
      if (prod) setSelectedProduct(prod);
    }
  }, []);

  const openProduct = useCallback((p: Product) => {
    setSelectedProduct(p);
    window.history.pushState({}, '', `?product=${p.id}`);
    // Блокируем скролл фона при открытии модалки
    document.body.style.overflow = 'hidden';
  }, []);

  const closeProduct = useCallback(() => {
    setSelectedProduct(null);
    window.history.pushState({}, '', window.location.pathname);
    document.body.style.overflow = 'auto';
  }, []);

  const addToCart = (product: Product, isWholesale: boolean) => {
    setCart(prevCart => {
      const existingIndex = prevCart.findIndex(item => item.id === product.id && item.isWholesale === isWholesale);

      if (existingIndex > -1) {
        const updatedCart = [...prevCart];
        updatedCart[existingIndex] = {
          ...updatedCart[existingIndex],
          quantity: updatedCart[existingIndex].quantity + (isWholesale ? 1 : 1) 
        };
        return updatedCart;
      } else {
        return [...prevCart, { 
          ...product, 
          quantity: isWholesale ? product.wholesaleMinQty : 1, 
          isWholesale 
        }];
      }
    });
  };

  const total = cart.reduce((acc, item) => 
    acc + (item.isWholesale ? item.priceWholesale : item.priceRetail) * item.quantity, 0
  );

  return (
    <div className="flex flex-col h-full max-w-md mx-auto bg-gray-50 relative border-x border-gray-200 min-h-[85vh] shadow-2xl rounded-[40px] overflow-hidden">
      {/* Product Modal Overlay - Rendered via Portals would be better, but we ensure absolute/fixed logic here */}
      {selectedProduct && (
        <ProductModal 
          product={selectedProduct} 
          lang={lang} 
          onClose={closeProduct} 
          onAddToCart={addToCart}
        />
      )}

      {/* Header */}
      <header className="bg-yellow-400 p-5 sticky top-0 z-40 shadow-sm">
        <div className="flex items-center justify-between mb-5">
          <div className="flex flex-col">
            <h1 className="text-xl font-black italic tracking-tighter text-black uppercase leading-none">{t.appTitle}</h1>
            <span className="text-[8px] font-black text-black/40 uppercase tracking-widest mt-1">Official Marketplace</span>
          </div>
          <div className="flex gap-3">
            <button className="bg-black/5 p-2 rounded-xl active:scale-90 transition-transform"><MessageCircle size={20} /></button>
            <button 
              onClick={() => setView('cart')}
              className="bg-black/5 p-2 rounded-xl relative active:scale-90 transition-transform"
            >
              <ShoppingCart size={20} />
              {cart.length > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-600 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center font-black border-2 border-yellow-400 animate-bounce">
                  {cart.length}
                </span>
              )}
            </button>
          </div>
        </div>
        <div className="relative group">
          <input 
            type="text" 
            placeholder={t.searchPlaceholder}
            className="w-full pl-11 pr-4 py-3 rounded-2xl bg-white border-2 border-transparent focus:border-black transition-all outline-none text-sm font-bold placeholder:text-gray-400 shadow-inner"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <Search className="absolute left-4 top-3.5 text-gray-400 group-focus-within:text-black transition-colors" size={18} />
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 p-5 pb-32 overflow-y-auto">
        {view === 'home' && (
          <div className="space-y-8">
            {/* Promo Banner */}
            <div className="bg-black text-white p-6 rounded-[32px] relative overflow-hidden group shadow-2xl">
              <div className="relative z-10">
                <div className="bg-yellow-400 text-black px-2 py-0.5 rounded text-[8px] font-black inline-block mb-3 uppercase tracking-tighter">Limited Offer</div>
                <h3 className="text-2xl font-black leading-tight mb-3">Get Free Delivery<br/>on 5,000,000 UZS+</h3>
                <button className="text-[10px] bg-white text-black font-black px-5 py-2 rounded-full uppercase transition-all hover:bg-yellow-400">Order Now</button>
              </div>
              <div className="absolute top-0 right-0 w-32 h-full bg-yellow-400/10 skew-x-12 -mr-12 transition-transform group-hover:translate-x-4"></div>
              <div className="absolute -bottom-4 -right-4 w-24 h-24 bg-yellow-400/20 rounded-full blur-2xl"></div>
            </div>

            {/* Products Grid */}
            <div className="grid grid-cols-2 gap-4">
              {MOCK_PRODUCTS.filter(p => p.name[lang].toLowerCase().includes(search.toLowerCase())).map(product => (
                <div 
                  key={product.id} 
                  className="bg-white rounded-[32px] overflow-hidden border border-gray-100 shadow-sm flex flex-col active:scale-95 transition-all cursor-pointer group hover:shadow-xl"
                  onClick={() => openProduct(product)}
                >
                  <div className="relative aspect-[4/5] overflow-hidden">
                    <img 
                      src={product.image} 
                      alt={product.name[lang]} 
                      className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" 
                      loading="lazy" 
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent"></div>
                    <button className="absolute top-3 right-3 bg-white/90 backdrop-blur-md p-2 rounded-full shadow-md hover:text-red-500 transition-colors">
                      <Heart size={14} />
                    </button>
                    {product.stock < 5 && (
                      <div className="absolute bottom-3 left-3 bg-red-600 text-white px-2 py-0.5 rounded-lg text-[8px] font-black uppercase shadow-lg">Last {product.stock} units</div>
                    )}
                  </div>
                  <div className="p-4 flex-1 flex flex-col">
                    <h3 className="text-xs font-black line-clamp-2 mb-2 text-gray-800 uppercase tracking-tight leading-tight">{product.name[lang]}</h3>
                    <div className="flex items-center gap-1.5 mb-3">
                      <div className="flex text-yellow-400">
                        <Star size={10} fill="currentColor" />
                      </div>
                      <span className="text-[10px] font-black text-black">{product.rating}</span>
                      <span className="text-[10px] font-bold text-gray-400">({product.totalReviews})</span>
                    </div>

                    <div className="mt-auto pt-3 border-t border-gray-50 flex flex-col gap-1">
                      <span className="text-[9px] text-gray-400 font-black uppercase tracking-widest">Price starting</span>
                      <span className="text-sm font-black text-gray-900 tracking-tighter">
                        {product.priceWholesale.toLocaleString()} <span className="text-[8px] font-normal opacity-50">UZS</span>
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {view === 'cart' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
             <div className="flex items-center gap-3 mb-6">
              <button onClick={() => setView('home')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-xl transition-colors"><ChevronRight className="rotate-180" size={20} /></button>
              <h2 className="text-xl font-black uppercase tracking-tighter">Your Basket</h2>
            </div>

            {cart.length === 0 ? (
              <div className="text-center py-20 flex flex-col items-center">
                <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                   <ShoppingCart size={32} className="text-gray-300" />
                </div>
                <p className="text-gray-400 font-bold italic">No items yet. Start building!</p>
              </div>
            ) : (
              <>
                <div className="space-y-4">
                  {cart.map((item, idx) => (
                    <div key={`${item.id}-${item.isWholesale}-${idx}`} className="flex gap-4 bg-white p-4 rounded-[28px] border border-gray-100 shadow-sm">
                      <img src={item.image} className="w-20 h-20 rounded-2xl object-cover shadow-sm" />
                      <div className="flex-1 flex flex-col justify-between">
                        <div>
                          <div className="flex justify-between items-start mb-1">
                            <h4 className="font-black text-xs text-gray-800 uppercase leading-none">{item.name[lang]}</h4>
                            {item.isWholesale && <span className="bg-black text-yellow-400 text-[8px] px-2 py-0.5 rounded-full font-black uppercase">Bulk</span>}
                          </div>
                          <div className="text-lg font-black text-gray-900 tracking-tighter">
                            {(item.isWholesale ? item.priceWholesale : item.priceRetail).toLocaleString()} <span className="text-[10px] font-normal">UZS</span>
                          </div>
                        </div>
                        <div className="flex items-center justify-between mt-2">
                          <div className="flex items-center gap-3 bg-gray-50 px-3 py-1 rounded-xl">
                             <button className="text-lg font-black" onClick={() => {
                               setCart(prev => prev.map((it, i) => i === idx ? {...it, quantity: Math.max(1, it.quantity - 1)} : it))
                             }}>-</button>
                             <span className="text-xs font-black">{item.quantity}</span>
                             <button className="text-lg font-black" onClick={() => {
                               setCart(prev => prev.map((it, i) => i === idx ? {...it, quantity: it.quantity + 1} : it))
                             }}>+</button>
                          </div>
                          <button className="text-[10px] text-red-500 font-black uppercase tracking-widest hover:underline" onClick={() => setCart(cart.filter((_, i) => i !== idx))}>Delete</button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="bg-white p-6 rounded-[32px] border border-gray-100 space-y-5 shadow-2xl mt-8 sticky bottom-0">
                  <div className="flex justify-between items-center bg-gray-50 p-3 rounded-2xl">
                    <span className="text-xs font-black text-gray-500 uppercase">{t.loaderService}</span>
                    <div className="w-10 h-5 bg-yellow-400 rounded-full relative cursor-pointer shadow-inner">
                       <div className="absolute right-1 top-1 w-3 h-3 bg-white rounded-full shadow-sm"></div>
                    </div>
                  </div>
                  <div className="pt-2 flex justify-between items-center">
                    <span className="text-gray-400 uppercase tracking-widest font-black text-[10px]">Grand Total</span>
                    <span className="text-2xl font-black text-black tracking-tighter">{total.toLocaleString()} UZS</span>
                  </div>
                  <button className="w-full py-5 bg-black text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl active:scale-95 transition-all hover:bg-gray-800">
                    {t.checkout}
                  </button>
                </div>
              </>
            )}
          </div>
        )}

        {view === 'profile' && (
          <div className="text-center py-10 space-y-6 animate-in zoom-in-95">
             <div className="w-24 h-24 bg-yellow-400 rounded-full mx-auto flex items-center justify-center text-3xl font-black shadow-xl">AK</div>
             <div>
               <h2 className="text-xl font-black tracking-tight">Alisher Karimov</h2>
               <p className="text-gray-500 font-bold">+998 90 123 45 67</p>
             </div>
             <div className="bg-white rounded-3xl p-2 border border-gray-100 shadow-sm space-y-1">
