                  <button key={item} className="w-full p-4 flex justify-between items-center hover:bg-gray-50 transition-colors rounded-2xl">
                    <span className="font-black text-xs uppercase tracking-widest">{item}</span>
                    <ChevronRight size={16} className="text-gray-300" />
