      {/* Navigation Bar */}
      <nav className="absolute bottom-6 left-1/2 -translate-x-1/2 w-[90%] bg-black/90 backdrop-blur-2xl rounded-full p-2 flex justify-around shadow-2xl z-40 border border-white/10">
