        <ProductModal 
          product={selectedProduct} 
          lang={lang} 
          onClose={closeProduct} 
          onAddToCart={addToCart}
        />
      )}

      <header className="bg-yellow-400 p-5 sticky top-0 z-40 shadow-sm">
        <div className="flex items-center justify-between mb-5">
          <div className="flex flex-col">
            <h1 className="text-xl font-black italic tracking-tighter text-black uppercase leading-none">{t.appTitle}</h1>
            <span className="text-[8px] font-black text-black/40 uppercase tracking-widest mt-1">Uzbekistan Premium</span>
          </div>
          <div className="flex gap-2">
            <button className="bg-black/5 p-2 rounded-xl active:scale-90 transition-transform"><MessageCircle size={18} /></button>
            <button 
              onClick={() => setView('cart')}
              className="bg-black/5 p-2 rounded-xl relative active:scale-90 transition-transform"
            >
              <ShoppingCart size={18} />
              {cart.length > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-600 text-white text-[9px] w-4 h-4 rounded-full flex items-center justify-center font-black">
                  {cart.length}
                </span>
              )}
            </button>
          </div>
        </div>
        <div className="relative">
          <input 
            type="text" 
            placeholder={t.searchPlaceholder}
            className="w-full pl-10 pr-4 py-2.5 rounded-xl bg-white border-none text-sm font-bold shadow-inner outline-none"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <Search className="absolute left-3.5 top-3 text-gray-400" size={16} />
        </div>
      </header>

      <main className="flex-1 p-5 pb-32 overflow-y-auto scroll-smooth">
        {view === 'home' && (
          <div className="space-y-6">
            <div className="bg-black text-white p-5 rounded-[32px] relative overflow-hidden shadow-xl">
              <div className="relative z-10">
                <div className="flex items-center gap-1.5 text-yellow-400 text-[8px] font-black uppercase mb-2">
                  <Zap size={10} fill="currentColor" />
                  <span>Flash Sale</span>
                </div>
                <h3 className="text-xl font-black leading-tight mb-2 tracking-tight">5,000,000 UZS+<br/>= {lang === 'ru' ? 'БЕСПЛАТНАЯ ДОСТАВКА' : 'BEPUL YETKAZISH'}</h3>
                <button className="text-[9px] bg-yellow-400 text-black font-black px-4 py-1.5 rounded-full uppercase transition-all">{t.details}</button>
              </div>
              <div className="absolute top-0 right-0 w-32 h-full bg-white/5 skew-x-12 -mr-16"></div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              {MOCK_PRODUCTS.filter(p => p.name[lang].toLowerCase().includes(search.toLowerCase())).map(product => (
                <div 
                  key={product.id} 
                  className="bg-white rounded-[28px] overflow-hidden border border-gray-100 shadow-sm flex flex-col active:scale-95 transition-all cursor-pointer group"
                  onClick={() => openProduct(product)}
                >
                  <div className="relative aspect-[4/5]">
                    <img src={product.image} className="w-full h-full object-cover transition-transform group-hover:scale-110" />
                    <button className="absolute top-3 right-3 bg-white/80 p-2 rounded-full shadow-md"><Heart size={12} /></button>
                    {product.stock < 10 && (
                      <div className="absolute bottom-2 left-2 bg-red-600 text-white px-2 py-0.5 rounded-lg text-[8px] font-black uppercase">{t.lowStock}</div>
                    )}
                  </div>
                  <div className="p-3 flex-1 flex flex-col">
                    <h3 className="text-[10px] font-black line-clamp-2 mb-2 text-gray-800 uppercase leading-tight">{product.name[lang]}</h3>
