        )}

        {view === 'cart' && (
          <div className="space-y-6">
            <h2 className="text-xl font-black uppercase tracking-tighter">{t.yourOrder}</h2>

            {cart.length === 0 ? (
              <div className="text-center py-20">
                <p className="text-gray-400 font-bold italic text-sm">{t.emptyCart}</p>
              </div>
            ) : (
              <div className="space-y-4">
                {cart.map((item, idx) => (
                  <div key={`${item.id}-${item.isWholesale}`} className="flex gap-3 bg-white p-3 rounded-2xl border border-gray-100">
                    <img src={item.image} className="w-16 h-16 rounded-xl object-cover" />
                    <div className="flex-1 flex flex-col justify-between">
                      <div className="flex justify-between items-start">
                        <h4 className="font-black text-[10px] uppercase text-gray-800 leading-tight pr-2">{item.name[lang]}</h4>
                        {item.isWholesale && <span className="bg-black text-yellow-400 text-[7px] px-1.5 py-0.5 rounded-full font-black uppercase">BULK</span>}
                      </div>
                      <div className="flex items-center justify-between mt-2">
                        <span className="text-xs font-black">{(item.isWholesale ? item.priceWholesale : item.priceRetail).toLocaleString()} UZS</span>
                        <div className="flex items-center gap-2 bg-gray-50 px-2 py-1 rounded-lg">
                           <button className="text-sm font-black w-4" onClick={() => updateQuantity(idx, -1)}>-</button>
                           <span className="text-[10px] font-black">{item.quantity}</span>
                           <button className="text-sm font-black w-4" onClick={() => updateQuantity(idx, 1)}>+</button>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}

                <div className="bg-white p-5 rounded-[32px] border border-gray-100 space-y-4 shadow-xl mt-6">
                  <div className="flex justify-between items-center text-[10px] font-black text-gray-400 uppercase">
