                   <div className="flex bg-white/10 p-2 rounded-xl border border-white/20 items-center justify-between">
                      <span className="font-black text-xs tracking-widest">STROY-2024</span>
                      <button className="bg-white text-blue-700 p-1.5 rounded-lg active:scale-90 transition-all">
                        <Copy size={14} />
