    e.stopPropagation();
    setProducts(prev => prev.map(p => p.id === id ? { ...p, isFavorite: !p.isFavorite } : p));
    // В реальном приложении здесь был бы API запрос
  };

  const addToCart = (product: Product, isWholesale: boolean, qty: number = 1) => {
    setCart(prevCart => {
      const existingIndex = prevCart.findIndex(item => item.id === product.id && item.isWholesale === isWholesale);
      if (existingIndex > -1) {
        const updated = [...prevCart];
        updated[existingIndex].quantity += qty;
        return updated;
      }
      return [...prevCart, { ...product, quantity: qty, isWholesale }];
    });
  };

  const total = cart.reduce((acc, item) => acc + (item.isWholesale ? item.priceWholesale : item.priceRetail) * item.quantity, 0);

