        <input 
          type="text" 
          placeholder={t.searchPlaceholder}
          className="w-full pl-4 pr-4 py-2.5 rounded-xl bg-white border-none text-sm font-bold shadow-inner outline-none"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
