import React, { useState } from 'react';
import { Product, Language, Review } from '../types';
import { TRANSLATIONS } from '../constants';
import { X, Star, CheckCircle, Package, TrendingUp, Minus, Plus } from 'lucide-react';

interface Props {
  product: Product;
  lang: Language;
  onClose: () => void;
  onAddToCart: (p: Product, isWholesale: boolean, qty: number) => void;
}

const ProductModal: React.FC<Props> = ({ product, lang, onClose, onAddToCart }) => {
  const [qty, setQty] = useState(1);
  const [isWholesale, setIsWholesale] = useState(false);
  const t = TRANSLATIONS[lang];

  const handleQtyChange = (delta: number) => {
    const newQty = qty + delta;
    if (newQty >= 1 && newQty <= product.stock) {
      setQty(newQty);
      // Авто-переключение на опт, если достигнут порог
      if (newQty >= product.wholesaleMinQty) setIsWholesale(true);
      else setIsWholesale(false);
    }
  };

  const currentPrice = isWholesale ? product.priceWholesale : product.priceRetail;

  return (
    <div className="fixed inset-0 z-[200] flex items-end sm:items-center justify-center bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
      <div className="absolute inset-0" onClick={onClose}></div>

      <div className="bg-white w-full max-w-2xl max-h-[90vh] rounded-t-[40px] sm:rounded-[40px] overflow-hidden flex flex-col shadow-2xl relative z-10 animate-in slide-in-from-bottom-10 duration-500">

        <button onClick={onClose} className="absolute top-6 right-6 z-[210] p-2 bg-gray-100 rounded-full shadow-lg">
          <X size={20} />
        </button>

        <div className="overflow-y-auto flex-1">
          <div className="grid grid-cols-1 md:grid-cols-2">
            <div className="relative aspect-square">
              <img src={product.image} className="w-full h-full object-cover" />
            </div>

            <div className="p-6 flex flex-col justify-between">
              <div>
                <h2 className="text-2xl font-black uppercase tracking-tighter mb-2">{product.name[lang]}</h2>
                <div className="flex items-center gap-2 mb-4">
                  <div className="flex text-yellow-400"><Star size={14} fill="currentColor" /></div>
                  <span className="font-black text-sm">{product.rating}</span>
                  <span className={`text-[9px] font-black uppercase px-2 py-1 rounded ${product.stock < 10 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
                    {product.stock} {t.leftInStock}
                  </span>
                </div>
              </div>

              {/* Quantity Selector */}
              <div className="bg-gray-50 p-4 rounded-3xl mb-4">
                <div className="text-[10px] font-black uppercase text-gray-400 mb-2">Количество</div>
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <button onClick={() => handleQtyChange(-1)} className="w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-sm active:scale-90 transition-transform">
                      <Minus size={16} />
                    </button>
                    <span className="text-xl font-black w-8 text-center">{qty}</span>
                    <button onClick={() => handleQtyChange(1)} className="w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-sm active:scale-90 transition-transform">
                      <Plus size={16} />
                    </button>
                  </div>
                  <div className="text-right">
                    <div className="text-xl font-black">{(currentPrice * qty).toLocaleString()}</div>
                    <div className="text-[8px] font-black text-gray-400 uppercase">Сумма UZS</div>
                  </div>
                </div>
              </div>

              <div className="flex flex-col gap-3">
                <div className={`p-4 rounded-2xl border-2 transition-all cursor-pointer ${!isWholesale ? 'border-black bg-black text-white' : 'border-gray-100 bg-white text-gray-400'}`} onClick={() => { setIsWholesale(false); setQty(1); }}>
                   <div className="text-[9px] font-black uppercase">{t.retail}</div>
                   <div className="font-black">{product.priceRetail.toLocaleString()} UZS</div>
                </div>
                <div className={`p-4 rounded-2xl border-2 transition-all cursor-pointer ${isWholesale ? 'border-yellow-400 bg-yellow-400 text-black' : 'border-gray-100 bg-white text-gray-400'}`} onClick={() => { setIsWholesale(true); setQty(product.wholesaleMinQty); }}>
                   <div className="text-[9px] font-black uppercase">{t.wholesale} (от {product.wholesaleMinQty} шт)</div>
                   <div className="font-black">{product.priceWholesale.toLocaleString()} UZS</div>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="p-6 bg-white border-t border-gray-50">
           <button 
             onClick={() => { onAddToCart(product, isWholesale, qty); onClose(); }}
             className="w-full py-5 bg-black text-white rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-xl active:scale-95 transition-all"
           >
             {t.addToCart}
           </button>
        </div>
      </div>
    </div>
  );
};

