import React, { useState, useCallback } from 'react';
import { Language, Product, CartItem } from '../types';
import { TRANSLATIONS } from '../constants';
import { ShoppingCart, Search, User, Home, Heart, MessageCircle, ChevronRight, Star, Copy, Zap, Loader2 } from 'lucide-react';
import ProductModal from './ProductModal';

interface Props {
  lang: Language;
  products: Product[];
  cart: CartItem[];
  onToggleFavorite: (id: string) => void;
  onUpdateCart: (cart: CartItem[]) => void;
}

const MarketplaceView: React.FC<Props> = ({ lang, products, cart, onToggleFavorite, onUpdateCart }) => {
  const [view, setView] = useState<'home' | 'cart' | 'profile'>('home');
  const [search, setSearch] = useState('');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [isSyncingFav, setIsSyncingFav] = useState<string | null>(null);
  const [isCheckingOut, setIsCheckingOut] = useState(false);
  const t = TRANSLATIONS[lang];

  // Исправление Race Condition: Блокировка кнопки до подтверждения "сервера"
  const toggleFavoriteWithLock = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (isSyncingFav) return;

    setIsSyncingFav(id);
    // Имитация задержки сети
    await new Promise(resolve => setTimeout(resolve, 400));
    onToggleFavorite(id);
    setIsSyncingFav(null);
  };

  const addToCart = (product: Product, isWholesale: boolean, qty: number = 1) => {
    // Двойная валидация: Проверка остатков
    if (qty > product.stock) {
      alert(lang === 'ru' ? 'Недостаточно товара на складе!' : 'Omborda yetarli tovar yo\'q!');
      return;
    }

    const existingIndex = cart.findIndex(item => item.id === product.id && item.isWholesale === isWholesale);
    let newCart: CartItem[];

    if (existingIndex > -1) {
      newCart = [...cart];
      const newTotalQty = newCart[existingIndex].quantity + qty;
      if (newTotalQty > product.stock) {
        alert(lang === 'ru' ? 'Превышен лимит остатков!' : 'Qoldiq limiti oshib ketdi!');
        return;
      }
      newCart[existingIndex].quantity = newTotalQty;
    } else {
      newCart = [...cart, { ...product, quantity: qty, isWholesale }];
    }
    onUpdateCart(newCart);
  };

  const removeFromCart = (idx: number) => {
    const newCart = cart.filter((_, i) => i !== idx);
    onUpdateCart(newCart);
  };

  // Решение Overselling: Финальная проверка перед оплатой
  const handleCheckout = async () => {
    setIsCheckingOut(true);
    // Имитация транзакционной проверки на сервере
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Имитация ошибки конкурентного доступа в 20% случаев
    if (Math.random() < 0.2) {
      alert(lang === 'ru' ? 'Ошибка! Товар был куплен другим пользователем.' : 'Xatolik! Tovar boshqa foydalanuvchi tomonidan sotib olindi.');
      setIsCheckingOut(false);
      return;
    }

    alert(lang === 'ru' ? 'Заказ успешно оформлен!' : 'Buyurtma muvaffaqiyatli rasmiylashtirildi!');
    onUpdateCart([]);
