import React, { useState } from 'react';
import { Language, Product, CartItem } from '../types';
import { TRANSLATIONS } from '../constants';
import { ShoppingCart, Search, User, Home, Heart, MessageCircle, ChevronRight, Star, Copy, Zap, Loader2, LifeBuoy } from 'lucide-react';
import ProductModal from './ProductModal';

interface Props {
  lang: Language;
  products: Product[];
  cart: CartItem[];
  onToggleFavorite: (id: string) => void;
  onUpdateCart: (cart: CartItem[]) => void;
}

const MarketplaceView: React.FC<Props> = ({ lang, products, cart, onToggleFavorite, onUpdateCart }) => {
  const [view, setView] = useState<'home' | 'cart' | 'profile'>('home');
  const [search, setSearch] = useState('');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [isSyncingFav, setIsSyncingFav] = useState<string | null>(null);
  const [isCheckingOut, setIsCheckingOut] = useState(false);
  const t = TRANSLATIONS[lang];

  const toggleFavoriteWithLock = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (isSyncingFav) return;
    setIsSyncingFav(id);
    await new Promise(resolve => setTimeout(resolve, 300));
    onToggleFavorite(id);
    setIsSyncingFav(null);
  };

  const addToCart = (product: Product, isWholesale: boolean, qty: number = 1) => {
    if (qty > product.stock) {
      alert(lang === 'ru' ? 'Недостаточно товара!' : 'Tovar yetarli emas!');
      return;
    }
    const existingIndex = cart.findIndex(item => item.id === product.id && item.isWholesale === isWholesale);
    let newCart: CartItem[];
    if (existingIndex > -1) {
      newCart = [...cart];
      newCart[existingIndex].quantity += qty;
    } else {
      newCart = [...cart, { ...product, quantity: qty, isWholesale }];
    }
    onUpdateCart(newCart);
  };

  const handleCheckout = async () => {
    setIsCheckingOut(true);
    await new Promise(resolve => setTimeout(resolve, 1000));
    alert(lang === 'ru' ? 'Заказ оформлен!' : 'Buyurtma rasmiylashtirildi!');
    onUpdateCart([]);
    setIsCheckingOut(false);
    setView('home');
  };

  const total = cart.reduce((acc, item) => acc + (item.isWholesale ? item.priceWholesale : item.priceRetail) * item.quantity, 0);

  return (
    <div className="flex flex-col h-full max-w-md mx-auto bg-gray-50 relative border-x border-gray-200 min-h-[85vh] shadow-2xl rounded-[40px] overflow-hidden">
      {selectedProduct && (
        <ProductModal 
          product={selectedProduct} 
          lang={lang} 
          onClose={() => setSelectedProduct(null)} 
          onAddToCart={addToCart}
        />
      )}

      <header className="bg-yellow-400 p-5 sticky top-0 z-40 shadow-sm">
        <div className="flex items-center justify-between mb-5">
