    const existingIndex = cart.findIndex(item => item.id === product.id && item.isWholesale === isWholesale);
    let newCart = [...cart];
    if (existingIndex > -1) newCart[existingIndex].quantity += qty;
    else newCart.push({ ...product, quantity: qty, isWholesale });
    onUpdateCart(newCart);
  };

  const filteredProducts = products.filter(p => {
    const matchesSearch = p.name[lang].toLowerCase().includes(search.toLowerCase());
    const matchesCategory = categoryFilter ? p.category === categoryFilter : true;
    return matchesSearch && matchesCategory;
