                  <button 
                    key={tab}
                    onClick={() => setActiveTab(tab as any)}
                    className={`pb-2 text-[10px] font-black uppercase transition-all border-b-2 ${activeTab === tab ? 'border-yellow-400 text-black' : 'border-transparent text-gray-400'}`}
                  >
                    {t[tab as keyof typeof t] || tab}
                  </button>
                ))}
              </div>

              <div className="flex-1 min-h-[120px] mb-4 text-[10px]">
                {activeTab === 'specs' ? (
                  <div className="space-y-1.5">
                    {product.attributes.map(attr => (
                      <div key={attr.key} className="flex justify-between border-b border-gray-50 pb-1">
                        <span className="text-gray-400 uppercase">{attr.label[lang]}</span>
                        <span className="font-bold">{attr.value}</span>
                      </div>
                    ))}
                    <p className="text-gray-500 mt-2 leading-relaxed">{product.description[lang]}</p>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {mockReviews.map(r => (
                      <div key={r.id} className="bg-gray-50 p-3 rounded-2xl">
                        <div className="flex justify-between mb-1">
                          <span className="font-black uppercase">{r.userName}</span>
                          {r.isVerified && <CheckCircle size={10} className="text-blue-500" />}
                        </div>
                        <p className="text-gray-600 leading-tight italic">"{r.comment}"</p>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              <div className="bg-gray-50 p-4 rounded-3xl mb-4">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <button onClick={() => handleQtyChange(-1)} disabled={qty <= 1} className="w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-sm disabled:opacity-30"><Minus size={16} /></button>
                    <span className="text-xl font-black w-8 text-center">{qty}</span>
                    <button onClick={() => handleQtyChange(1)} disabled={qty >= product.stock} className="w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-sm disabled:opacity-30"><Plus size={16} /></button>
                  </div>
                  <div className="text-right">
                    <div className="text-lg font-black">{Math.round((isWholesale ? product.priceWholesale : product.priceRetail) * qty).toLocaleString()}</div>
                    <div className="text-[8px] font-black text-gray-400 uppercase">UZS</div>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-2">
                <button 
                  onClick={() => { setIsWholesale(false); setQty(1); }}
                  className={`p-3 rounded-2xl border-2 transition-all text-left ${!isWholesale ? 'border-black bg-black text-white shadow-lg' : 'border-gray-100 bg-white text-gray-400'}`}
                >
                  <div className="text-[7px] font-black uppercase">{t.retail}</div>
                  <div className="font-black text-xs">{product.priceRetail.toLocaleString()}</div>
                </button>
                <button 
                  onClick={() => { setIsWholesale(true); setQty(product.wholesaleMinQty); }}
                  className={`p-3 rounded-2xl border-2 transition-all text-left ${isWholesale ? 'border-yellow-400 bg-yellow-400 text-black shadow-lg' : 'border-gray-100 bg-white text-gray-400'}`}
                >
                  <div className="text-[7px] font-black uppercase">{t.wholesale} ({product.wholesaleMinQty}+)</div>
                  <div className="font-black text-xs">{product.priceWholesale.toLocaleString()}</div>
                </button>
              </div>
            </div>
          </div>
        </div>

        <div className="p-6 bg-white border-t border-gray-50">
           <button 
             onClick={() => { onAddToCart(product, isWholesale, qty); onClose(); }}
             className="w-full py-4 bg-black text-white rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-xl active:scale-95 transition-all"
           >
             {t.addToCart}
           </button>
        </div>
      </div>
    </div>
  );
};

