        <button 
          onClick={() => setView('categories')} 
          className={`p-4 rounded-2xl transition-all duration-300 ${view === 'categories' ? 'bg-yellow-400 text-black scale-110 shadow-xl' : 'text-white/40 hover:text-white'}`}
        >
          <LayoutGrid size={20} />
        </button>
        <button 
          onClick={() => setView('cart')} 
          className={`p-4 rounded-2xl transition-all duration-300 ${view === 'cart' ? 'bg-yellow-400 text-black scale-110 shadow-xl' : 'text-white/40 hover:text-white'}`}
        >
          <ShoppingCart size={20} />
        </button>
        <button 
          onClick={() => setView('profile')} 
          className={`p-4 rounded-2xl transition-all duration-300 ${view === 'profile' || view === 'fav_list' ? 'bg-yellow-400 text-black scale-110 shadow-xl' : 'text-white/40 hover:text-white'}`}
