import React, { useState, useEffect } from 'react';
import { Language, Product, CartItem } from './types';
import { TRANSLATIONS, MOCK_PRODUCTS } from './constants';
import MarketplaceView from './components/MarketplaceView';
import ArchitectView from './components/ArchitectView';
import { Layout, AppWindow, Database } from 'lucide-react';

export type ViewState = 'home' | 'categories' | 'cart' | 'profile' | 'fav_list';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('se_lang') as Language) || 'ru';
  });
  const [mode, setMode] = useState<'app' | 'architect'>('app');

  // Состояние навигации вынесено в App
  const [view, setView] = useState<ViewState>(() => {
    return (localStorage.getItem('se_view') as ViewState) || 'home';
  });
  const [categoryFilter, setCategoryFilter] = useState<string | null>(null);

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('se_products');
    return saved ? JSON.parse(saved) : MOCK_PRODUCTS;
  });

  const [cart, setCart] = useState<CartItem[]>(() => {
    const saved = localStorage.getItem('se_cart');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('se_lang', lang);
  }, [lang]);

  useEffect(() => {
    localStorage.setItem('se_view', view);
  }, [view]);

  useEffect(() => {
    localStorage.setItem('se_cart', JSON.stringify(cart));
  }, [cart]);

  useEffect(() => {
    localStorage.setItem('se_products', JSON.stringify(products));
  }, [products]);

  const t = TRANSLATIONS[lang];

  const handleToggleFavorite = (id: string) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, isFavorite: !p.isFavorite } : p));
  };

  const handleUpdateCart = (newCart: CartItem[]) => {
    setCart(newCart);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans selection:bg-yellow-200">
      <nav className="bg-white/90 backdrop-blur-md border-b border-gray-200 px-4 py-2 sticky top-0 z-[100] shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setMode('app')}>
            <div className="bg-yellow-400 p-1.5 rounded-lg">
              <Layout size={18} className="text-black" />
            </div>
            <span className="font-black text-base hidden sm:block tracking-tighter uppercase">StroyExpress</span>
          </div>

          <div className="hidden md:flex bg-gray-100 p-1 rounded-xl">
            <button 
              onClick={() => setMode('app')}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${mode === 'app' ? 'bg-white shadow-sm text-black' : 'text-gray-500 hover:text-gray-700'}`}
            >
              <AppWindow size={14} />
              {t.appMode.toUpperCase()}
            </button>
            <button 
              onClick={() => setMode('architect')}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${mode === 'architect' ? 'bg-white shadow-sm text-black' : 'text-gray-500 hover:text-gray-700'}`}
            >
              <Database size={14} />
              {t.schemaMode.toUpperCase()}
            </button>
          </div>
        </div>

        <div className="flex items-center">
          <div className="flex bg-gray-100 p-0.5 rounded-xl border border-gray-200 overflow-hidden">
            <button 
              onClick={() => setLang('ru')}
              className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${lang === 'ru' ? 'bg-black text-white shadow-sm' : 'text-gray-500 hover:bg-gray-200'}`}
            >
              RU
            </button>
            <button 
              onClick={() => setLang('uz')}
              className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${lang === 'uz' ? 'bg-black text-white shadow-sm' : 'text-gray-500 hover:bg-gray-200'}`}
            >
              UZ
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1 overflow-x-hidden">
        {mode === 'app' ? (
          <div className="py-6 px-4">
