import React, { useState } from 'react';
import { Language, Product, CartItem } from '../types';
import { TRANSLATIONS } from '../constants';
import { ShoppingCart, Search, User, Home, Heart, MessageCircle, ChevronRight, Star, Copy, Zap, LayoutGrid, LifeBuoy, Hammer, Plug, PaintBucket, BrickWall, ArrowLeft } from 'lucide-react';
import ProductModal from './ProductModal';
import { ViewState } from '../App';

interface Props {
  lang: Language;
  products: Product[];
  cart: CartItem[];
  view: ViewState;
  setView: (v: ViewState) => void;
  categoryFilter: string | null;
  setCategoryFilter: (c: string | null) => void;
  onToggleFavorite: (id: string) => void;
  onUpdateCart: (cart: CartItem[]) => void;
}

const MarketplaceView: React.FC<Props> = ({ 
  lang, 
  products, 
  cart, 
  view, 
  setView, 
  categoryFilter, 
  setCategoryFilter, 
  onToggleFavorite, 
  onUpdateCart 
}) => {
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [search, setSearch] = useState('');
  const t = TRANSLATIONS[lang];

  // Исправленная функция: теперь при добавлении в корзину через модалку 
  // мы можем переключить экран на 'cart', если это потребуется
  const addToCart = (product: Product, isWholesale: boolean, qty: number = 1) => {
    const existingIndex = cart.findIndex(item => item.id === product.id && item.isWholesale === isWholesale);
    let newCart = [...cart];
    if (existingIndex > -1) {
      newCart[existingIndex].quantity += qty;
    } else {
      newCart.push({ ...product, quantity: qty, isWholesale });
    }
    onUpdateCart(newCart);

    // Переходим в корзину сразу после добавления, как просил пользователь
    setView('cart');
    setCategoryFilter(null);
  };

  const handleOpenCart = () => {
    setView('cart');
    setCategoryFilter(null);
  };

  const filteredProducts = products.filter(p => {
    const matchesSearch = p.name[lang].toLowerCase().includes(search.toLowerCase());
    const matchesCategory = categoryFilter ? p.category === categoryFilter : true;
    return matchesSearch && matchesCategory;
  });

  const favoriteProducts = products.filter(p => p.isFavorite);

  const CategoriesGrid = () => (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
      <h2 className="text-xl font-black uppercase mb-6 tracking-tighter">{t.categories}</h2>
      <div className="grid grid-cols-2 gap-4">
        {[
          { id: 'materials', icon: BrickWall, label: t.materials, color: 'bg-orange-100 text-orange-600' },
          { id: 'tools', icon: Hammer, label: t.tools, color: 'bg-blue-100 text-blue-600' },
          { id: 'electrical', icon: Plug, label: t.electrical, color: 'bg-yellow-100 text-yellow-600' },
          { id: 'finishing', icon: PaintBucket, label: t.finishing, color: 'bg-purple-100 text-purple-600' },
        ].map(cat => (
          <button 
            key={cat.id} 
            onClick={() => { setCategoryFilter(cat.id); setView('home'); }}
            className="flex flex-col items-center justify-center p-6 bg-white rounded-[32px] border border-gray-100 shadow-sm active:scale-95 transition-all hover:border-yellow-400 group"
          >
            <div className={`p-4 rounded-2xl mb-3 transition-transform group-hover:scale-110 ${cat.color}`}><cat.icon size={28} /></div>
            <span className="font-black text-[10px] uppercase tracking-wider">{cat.label}</span>
          </button>
        ))}
      </div>
    </div>
  );

  return (
    <div className="flex flex-col h-full max-w-md mx-auto bg-gray-50 relative border-x border-gray-200 min-h-[85vh] shadow-2xl rounded-[40px] overflow-hidden">
      {selectedProduct && (
        <ProductModal 
          product={selectedProduct} 
          lang={lang} 
          onClose={() => setSelectedProduct(null)} 
          onAddToCart={addToCart}
        />
      )}

      <header className="bg-yellow-400 p-5 sticky top-0 z-40 shadow-sm">
        <div className="flex items-center justify-between mb-4">
          <div onClick={() => { setView('home'); setCategoryFilter(null); }} className="cursor-pointer">
            <h1 className="text-xl font-black italic text-black uppercase leading-none">{t.appTitle}</h1>
          </div>
          <div className="flex gap-2">
            <button onClick={() => alert(t.chatWithSeller)} className="bg-black/10 p-2 rounded-xl relative active:scale-90 transition-all text-black">
              <MessageCircle size={18} />
              <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-red-600 rounded-full border-2 border-yellow-400"></span>
            </button>
            <button 
              onClick={handleOpenCart} 
              className={`p-2 rounded-xl relative transition-all active:scale-90 ${view === 'cart' ? 'bg-black text-white shadow-lg' : 'bg-black/10 text-black'}`}
            >
              <ShoppingCart size={18} />
              {cart.length > 0 && (
                <span className="absolute -top-1 -right-1 bg-red-600 text-white text-[9px] w-4 h-4 rounded-full flex items-center justify-center font-black animate-in zoom-in">
                  {cart.length}
                </span>
              )}
            </button>
          </div>
        </div>
        <div className="relative">
          <Search className="absolute left-3 top-3 text-gray-500" size={16} />
          <input 
            type="text" 
            placeholder={t.searchPlaceholder}
            className="w-full pl-10 pr-4 py-3 rounded-xl bg-white border-none text-sm font-bold shadow-inner outline-none focus:ring-2 focus:ring-black/5"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
      </header>

      <main className="flex-1 p-5 pb-32 overflow-y-auto scrollbar-hide">
        {view === 'home' && (
          <div className="space-y-4">
            {categoryFilter && (
              <div className="flex items-center justify-between bg-black text-white p-3 rounded-2xl shadow-lg animate-in slide-in-from-top-2">
                <div className="flex items-center gap-2">
                  <LayoutGrid size={14} className="text-yellow-400" />
                  <span className="text-[10px] font-black uppercase tracking-widest">{t[categoryFilter as keyof typeof t] || categoryFilter}</span>
                </div>
                <button onClick={() => setCategoryFilter(null)} className="p-1 hover:bg-white/20 rounded-lg transition-colors">
                  <ArrowLeft size={14} />
                </button>
              </div>
            )}
            <div className="grid grid-cols-2 gap-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
              {filteredProducts.map(product => (
                <div key={product.id} className="bg-white rounded-[28px] overflow-hidden border border-gray-100 shadow-sm flex flex-col active:scale-95 transition-all cursor-pointer group" onClick={() => setSelectedProduct(product)}>
