          </div>
        </div>

        <div className="flex items-center">
          <div className="flex bg-gray-100 p-0.5 rounded-xl border border-gray-200 overflow-hidden">
            <button 
              onClick={() => setLang('ru')}
              className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${lang === 'ru' ? 'bg-black text-white shadow-sm' : 'text-gray-500 hover:bg-gray-200'}`}
            >
              RU
            </button>
            <button 
              onClick={() => setLang('uz')}
              className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${lang === 'uz' ? 'bg-black text-white shadow-sm' : 'text-gray-500 hover:bg-gray-200'}`}
            >
              UZ
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1">
        {mode === 'app' ? (
          <div className="w-full max-w-7xl mx-auto py-6 px-4 md:px-8 lg:px-12">
             <div className="mb-6 text-center">
                <h2 className="text-2xl md:text-3xl lg:text-4xl font-black text-gray-900 mb-2 tracking-tight">StroyExpress</h2>
                <p className="text-gray-500 text-[10px] md:text-xs font-bold leading-relaxed uppercase tracking-widest">
                  {lang === 'ru' ? 'Твой надежный склад материалов' : 'Sizning ishonchli materiallar omboringiz'}
                </p>
             </div>
             <MarketplaceView 
               lang={lang} 
               products={products}
               cart={cart}
               view={view}
               setView={setView}
               categoryFilter={categoryFilter}
               setCategoryFilter={setCategoryFilter}
               onToggleFavorite={handleToggleFavorite}
               onUpdateCart={handleUpdateCart}
             />
          </div>
        ) : (
          <ArchitectView />
        )}
      </main>

      <footer className="bg-white border-t border-gray-100 py-12 text-center">
        <p className="text-gray-400 text-[9px] font-black uppercase tracking-[0.2em]">
          StroyExpress Systems Architecture 2024
        </p>
      </footer>
    </div>
  );
};

