  setView, 
  theme,
  categoryFilter, 
  setCategoryFilter, 
  onToggleFavorite, 
  onUpdateCart 
}) => {
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [search, setSearch] = useState('');
  const t = TRANSLATIONS[lang];

  const addToCart = (product: Product, isWholesale: boolean, qty: number = 1) => {
    const existingIndex = cart.findIndex(item => item.id === product.id && item.isWholesale === isWholesale);
    let newCart = [...cart];
    if (existingIndex > -1) {
      newCart[existingIndex].quantity += qty;
    } else {
      newCart.push({ ...product, quantity: qty, isWholesale });
    }
    onUpdateCart(newCart);

    // Переход в корзину
    setView('cart');
    setCategoryFilter(null);
    setSelectedProduct(null);
  };

  const handleOpenCart = () => {
    setView('cart');
    setCategoryFilter(null);
  };

  const filteredProducts = products.filter(p => {
    const matchesSearch = p.name[lang].toLowerCase().includes(search.toLowerCase());
    const matchesCategory = categoryFilter ? p.category === categoryFilter : true;
    return matchesSearch && matchesCategory;
  });

  const favoriteProducts = products.filter(p => p.isFavorite);

  const CategoriesGrid = () => (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-300 max-w-4xl mx-auto">
