                  className={`p-4 rounded-2xl border-2 transition-all text-left relative overflow-hidden group ${isWholesale ? 'border-yellow-400 bg-yellow-400 text-black shadow-xl' : (theme === 'dark' ? 'border-zinc-800 bg-zinc-800 text-zinc-500 hover:border-zinc-700' : 'border-gray-200 bg-white text-gray-400 hover:border-gray-300')}`}
                >
                  <div className="text-[8px] font-black uppercase tracking-widest mb-1">{t.wholesale} ({product.wholesaleMinQty}+)</div>
                  <div className="font-black text-sm">{product.priceWholesale.toLocaleString()}</div>
                  {isWholesale && <Zap size={40} className="absolute -bottom-4 -right-4 opacity-20" />}
                </button>
              </div>
            </div>
          </div>
        </div>

        <div className={`p-6 border-t transition-colors duration-300 ${theme === 'dark' ? 'bg-zinc-900 border-zinc-800' : 'bg-white border-gray-100'}`}>
           <button 
             onClick={() => { onAddToCart(product, isWholesale, qty || 1); onClose(); }}
             className="w-full py-5 bg-yellow-400 text-black rounded-2xl font-black uppercase tracking-[0.2em] text-[11px] shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-3 hover:bg-yellow-500"
           >
             <ShoppingCart size={18} />
             {t.addToCart}
           </button>
        </div>
      </div>
    </div>
  );
};

export default ProductModal;

import React, { useState, useEffect } from 'react';
import { Language, Product, CartItem } from './types';
import { TRANSLATIONS, MOCK_PRODUCTS } from './constants';
import MarketplaceView from './components/MarketplaceView';
import ArchitectView from './components/ArchitectView';
import { Layout, AppWindow, Database, Moon, Sun } from 'lucide-react';

export type ViewState = 'home' | 'categories' | 'cart' | 'profile' | 'fav_list' | 'chat';
export type Theme = 'light' | 'dark';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('se_lang') as Language) || 'ru';
  });
  const [theme, setTheme] = useState<Theme>(() => {
    return (localStorage.getItem('se_theme') as Theme) || 'light';
  });
  const [mode, setMode] = useState<'app' | 'architect'>('app');

  const [view, setView] = useState<ViewState>(() => {
    return (localStorage.getItem('se_view') as ViewState) || 'home';
  });
  const [categoryFilter, setCategoryFilter] = useState<string | null>(null);

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('se_products');
    return saved ? JSON.parse(saved) : MOCK_PRODUCTS;
  });

  const [cart, setCart] = useState<CartItem[]>(() => {
    const saved = localStorage.getItem('se_cart');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('se_lang', lang);
  }, [lang]);

  useEffect(() => {
    localStorage.setItem('se_theme', theme);
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('se_view', view);
  }, [view]);

  useEffect(() => {
    localStorage.setItem('se_cart', JSON.stringify(cart));
  }, [cart]);

  useEffect(() => {
    localStorage.setItem('se_products', JSON.stringify(products));
  }, [products]);

  const t = TRANSLATIONS[lang];

  const handleToggleFavorite = (id: string) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, isFavorite: !p.isFavorite } : p));
  };

  const handleUpdateCart = (newCart: CartItem[]) => {
    setCart(newCart);
  };

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  return (
    <div className={`min-h-screen flex flex-col font-sans transition-colors duration-300 ${theme === 'dark' ? 'bg-zinc-950 text-white' : 'bg-gray-50 text-gray-900'}`}>
      <nav className={`border-b px-4 py-2 sticky top-0 z-[100] shadow-sm flex items-center justify-between backdrop-blur-md transition-colors duration-300 ${theme === 'dark' ? 'bg-zinc-900/90 border-zinc-800' : 'bg-white/90 border-gray-200'}`}>
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => { setMode('app'); setView('home'); }}>
            <div className="bg-yellow-400 p-1.5 rounded-lg">
              <Layout size={18} className="text-black" />
            </div>
            <span className={`font-black text-base hidden sm:block tracking-tighter uppercase ${theme === 'dark' ? 'text-white' : 'text-black'}`}>StroyExpress</span>
          </div>

          <div className={`hidden md:flex p-1 rounded-xl transition-colors duration-300 ${theme === 'dark' ? 'bg-zinc-800' : 'bg-gray-100'}`}>
            <button 
              onClick={() => setMode('app')}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${mode === 'app' ? (theme === 'dark' ? 'bg-zinc-700 text-white shadow-sm' : 'bg-white shadow-sm text-black') : 'text-gray-500 hover:text-gray-400'}`}
            >
              <AppWindow size={14} />
              {t.appMode.toUpperCase()}
            </button>
            <button 
              onClick={() => setMode('architect')}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${mode === 'architect' ? (theme === 'dark' ? 'bg-zinc-700 text-white shadow-sm' : 'bg-white shadow-sm text-black') : 'text-gray-500 hover:text-gray-400'}`}
            >
              <Database size={14} />
              {t.schemaMode.toUpperCase()}
            </button>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={toggleTheme}
            className={`p-2 rounded-xl transition-all active:scale-90 ${theme === 'dark' ? 'bg-zinc-800 text-yellow-400' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
            aria-label="Toggle Theme"
          >
            {theme === 'light' ? <Moon size={18} /> : <Sun size={18} />}
          </button>

          <div className={`flex p-0.5 rounded-xl border transition-colors duration-300 overflow-hidden ${theme === 'dark' ? 'bg-zinc-800 border-zinc-700' : 'bg-gray-100 border-gray-200'}`}>
            <button 
              onClick={() => setLang('ru')}
              className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${lang === 'ru' ? (theme === 'dark' ? 'bg-white text-black' : 'bg-black text-white') : 'text-gray-500 hover:bg-zinc-700 hover:text-white'}`}
            >
              RU
            </button>
            <button 
              onClick={() => setLang('uz')}
              className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${lang === 'uz' ? (theme === 'dark' ? 'bg-white text-black' : 'bg-black text-white') : 'text-gray-500 hover:bg-zinc-700 hover:text-white'}`}
            >
              UZ
            </button>
          </div>
        </div>
      </nav>

      <main className="flex-1">
        {mode === 'app' ? (
          <div className="w-full max-w-7xl mx-auto py-6 px-4 md:px-8 lg:px-12">
             <div className="mb-6 text-center">
                <h2 className={`text-2xl md:text-3xl lg:text-4xl font-black mb-2 tracking-tight transition-colors duration-300 ${theme === 'dark' ? 'text-white' : 'text-gray-900'}`}>StroyExpress</h2>
                <p className="text-gray-500 text-[10px] md:text-xs font-bold leading-relaxed uppercase tracking-widest">
                  {lang === 'ru' ? 'Твой надежный склад материалов' : 'Sizning ishonchli materiallar omboringiz'}
                </p>
             </div>
             <MarketplaceView 
               lang={lang} 
               products={products}
               cart={cart}
               view={view}
               setView={setView}
               theme={theme}
               categoryFilter={categoryFilter}
               setCategoryFilter={setCategoryFilter}
               onToggleFavorite={handleToggleFavorite}
               onUpdateCart={handleUpdateCart}
             />
          </div>
        ) : (
          <ArchitectView />
        )}
      </main>

      <footer className={`border-t py-12 text-center transition-colors duration-300 ${theme === 'dark' ? 'bg-zinc-950 border-zinc-900 text-zinc-600' : 'bg-white border-gray-100 text-gray-400'}`}>
        <p className="text-[9px] font-black uppercase tracking-[0.2em]">
          StroyExpress Systems Architecture 2024
        </p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Language, Product, CartItem } from '../types';
import { TRANSLATIONS } from '../constants';
import { ShoppingCart, Search, User, Home, Heart, MessageCircle, Star, Zap, LayoutGrid, LifeBuoy, Hammer, Plug, PaintBucket, BrickWall, ArrowLeft, Store, Headset, Send, Paperclip, CheckCheck } from 'lucide-react';
import ProductModal from './ProductModal';
import { ViewState, Theme } from '../App';

interface Message {
  id: string;
  text: string;
  sender: 'me' | 'other';
  time: string;
}

interface Chat {
  id: string;
  name: string;
  lastMessage: string;
  time: string;
  unread: number;
  type: 'support' | 'shop';
  avatar?: string;
}

interface Props {
  lang: Language;
  products: Product[];
  cart: CartItem[];
  view: ViewState;
  setView: (v: ViewState) => void;
  theme: Theme;
  categoryFilter: string | null;
  setCategoryFilter: (c: string | null) => void;
  onToggleFavorite: (id: string) => void;
  onUpdateCart: (cart: CartItem[]) => void;
}

const MarketplaceView: React.FC<Props> = ({ 
  lang, products, cart, view, setView, theme, 
  categoryFilter, setCategoryFilter, onToggleFavorite, onUpdateCart 
}) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [activeChatTab, setActiveChatTab] = useState<'support' | 'shops'>('support');
  const [activeChatId, setActiveChatId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([
    { id: '1', text: lang === 'ru' ? 'Здравствуйте! Чем могу помочь?' : 'Salom! Qanday yordam bera olaman?', sender: 'other', time: '10:00' }
  ]);
  const [newMessage, setNewMessage] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);
  const t = TRANSLATIONS[lang];

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, activeChatId]);

  const mockChats: Chat[] = [
    { id: 'support_1', name: t.techSupport, lastMessage: 'Ваш тикет №452 закрыт', time: '12:45', unread: 1, type: 'support' },
    { id: 'shop_1', name: 'Artel Official', lastMessage: 'Товар в наличии', time: 'Вчера', unread: 0, type: 'shop' },
    { id: 'shop_2', name: 'Knauf Uzbekistan', lastMessage: 'Скидка на опт 5%', time: '10.03', unread: 0, type: 'shop' },
  ];

  const filteredProducts = products.filter(p => {
    const matchesCategory = categoryFilter ? p.category === categoryFilter : true;
    const matchesSearch = p.name[lang].toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const handleSendMessage = () => {
    if (!newMessage.trim()) return;
    const msg: Message = {
      id: Date.now().toString(),
      text: newMessage,
      sender: 'me',
      time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    setMessages(prev => [...prev, msg]);
    setNewMessage('');

    // Имитация ответа
    setTimeout(() => {
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        text: lang === 'ru' ? 'Принято, ожидайте ответа.' : 'Qabul qilindi, javobni kuting.',
        sender: 'other',
        time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }]);
    }, 1500);
  };

  const renderChatView = () => {
    if (activeChatId) {
      const currentChat = mockChats.find(c => c.id === activeChatId);
      return (
        <div className={`flex flex-col h-[calc(100vh-200px)] rounded-3xl overflow-hidden border transition-colors duration-300 ${theme === 'dark' ? 'bg-zinc-900 border-zinc-800' : 'bg-white border-gray-100'}`}>
          {/* Chat Header */}
          <div className={`p-4 border-b flex items-center justify-between ${theme === 'dark' ? 'border-zinc-800 bg-zinc-900/50' : 'border-gray-100 bg-gray-50'}`}>
            <div className="flex items-center gap-3">
              <button onClick={() => setActiveChatId(null)} className="p-2 hover:bg-zinc-200/20 rounded-full transition-colors">
                <ArrowLeft size={20} />
              </button>
              <div>
                <h3 className="font-black text-sm uppercase">{currentChat?.name}</h3>
                <span className="text-[10px] text-green-500 font-bold uppercase tracking-widest">{t.supportOnline}</span>
              </div>
            </div>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
            {messages.map((msg) => (
              <div key={msg.id} className={`flex ${msg.sender === 'me' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-4 rounded-[24px] shadow-sm relative ${
                  msg.sender === 'me' 
                    ? 'bg-yellow-400 text-black rounded-tr-none' 
                    : (theme === 'dark' ? 'bg-zinc-800 text-white rounded-tl-none' : 'bg-gray-100 text-black rounded-tl-none')
                }`}>
                  <p className="text-sm font-medium leading-relaxed">{msg.text}</p>
                  <div className={`text-[8px] mt-1 flex items-center gap-1 font-bold ${msg.sender === 'me' ? 'text-black/50' : 'text-gray-500'}`}>
                    {msg.time}
                    {msg.sender === 'me' && <CheckCheck size={10} />}
                  </div>
                </div>
              </div>
            ))}
            <div ref={chatEndRef} />
          </div>

          {/* Chat Input */}
          <div className={`p-4 border-t flex items-center gap-3 ${theme === 'dark' ? 'border-zinc-800 bg-zinc-900' : 'border-gray-100 bg-white'}`}>
            <button className={`p-3 rounded-2xl transition-colors ${theme === 'dark' ? 'hover:bg-zinc-800 text-zinc-500' : 'hover:bg-gray-100 text-gray-400'}`}>
              <Paperclip size={20} />
            </button>
            <input 
              value={newMessage}
              onChange={(e) => setNewMessage(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder={t.searchPlaceholder}
              className={`flex-1 bg-transparent py-3 px-4 rounded-2xl font-medium outline-none border-2 transition-all ${
                theme === 'dark' ? 'border-zinc-800 focus:border-yellow-400 text-white' : 'border-gray-100 focus:border-yellow-400'
              }`}
            />
            <button 
              onClick={handleSendMessage}
              className="p-4 bg-yellow-400 text-black rounded-2xl active:scale-95 transition-all shadow-lg"
            >
              <Send size={20} />
            </button>
          </div>
        </div>
      );
    }

    return (
      <div className="space-y-6">
        <div className={`flex p-1 rounded-2xl transition-colors duration-300 ${theme === 'dark' ? 'bg-zinc-900' : 'bg-gray-100'}`}>
          <button 
            onClick={() => setActiveChatTab('support')}
            className={`flex-1 flex items-center justify-center gap-2 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeChatTab === 'support' ? (theme === 'dark' ? 'bg-zinc-800 text-white shadow-xl' : 'bg-white text-black shadow-md') : 'text-gray-500'
            }`}
          >
            <Headset size={16} /> {t.techSupport}
          </button>
          <button 
            onClick={() => setActiveChatTab('shops')}
            className={`flex-1 flex items-center justify-center gap-2 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
              activeChatTab === 'shops' ? (theme === 'dark' ? 'bg-zinc-800 text-white shadow-xl' : 'bg-white text-black shadow-md') : 'text-gray-500'
            }`}
          >
            <Store size={16} /> {lang === 'ru' ? 'Магазины' : 'Do\'konlar'}
          </button>
        </div>

        <div className="space-y-2">
          {mockChats.filter(c => activeChatTab === 'support' ? c.type === 'support' : c.type === 'shop').map(chat => (
            <div 
              key={chat.id}
              onClick={() => setActiveChatId(chat.id)}
              className={`p-5 rounded-3xl border flex items-center justify-between cursor-pointer transition-all active:scale-[0.98] ${
                theme === 'dark' ? 'bg-zinc-900 border-zinc-800 hover:border-zinc-700' : 'bg-white border-gray-100 hover:border-gray-200 shadow-sm'
              }`}
            >
              <div className="flex items-center gap-4">
                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-inner ${theme === 'dark' ? 'bg-zinc-800' : 'bg-gray-50'}`}>
                  {chat.type === 'support' ? <LifeBuoy className="text-yellow-400" /> : <Store className="text-blue-500" />}
                </div>
                <div>
                  <h3 className={`font-black text-sm uppercase tracking-tight ${theme === 'dark' ? 'text-white' : 'text-gray-900'}`}>{chat.name}</h3>
                  <p className="text-xs text-gray-500 font-medium truncate max-w-[180px]">{chat.lastMessage}</p>
                </div>
              </div>
              <div className="text-right">
                <div className="text-[10px] font-bold text-gray-400 mb-1">{chat.time}</div>
                {chat.unread > 0 && (
                  <div className="bg-yellow-400 text-black text-[9px] font-black w-5 h-5 rounded-full flex items-center justify-center ml-auto">
                    {chat.unread}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="pb-24 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {view === 'home' && (
        <>
          <div className="relative mb-8 group">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-gray-400 transition-colors group-focus-within:text-yellow-400" size={20} />
            <input 
              type="text"
              placeholder={t.searchPlaceholder}
              className={`w-full py-6 pl-16 pr-6 rounded-[32px] text-sm font-bold outline-none border-2 transition-all shadow-xl ${
                theme === 'dark' ? 'bg-zinc-900 border-zinc-800 text-white focus:border-yellow-400' : 'bg-white border-gray-100 focus:border-yellow-400'
              }`}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-4 gap-4 mb-10 overflow-x-auto pb-4 no-scrollbar">
            {[
              { id: 'materials', icon: BrickWall, label: t.materials },
              { id: 'tools', icon: Hammer, label: t.tools },
              { id: 'electrical', icon: Plug, label: t.electrical },
              { id: 'finishing', icon: PaintBucket, label: t.finishing }
            ].map(cat => (
              <button 
                key={cat.id}
                onClick={() => setCategoryFilter(categoryFilter === cat.id ? null : cat.id)}
                className={`flex flex-col items-center justify-center p-6 rounded-[40px] transition-all min-w-[100px] border-2 ${
                  categoryFilter === cat.id 
                    ? 'bg-yellow-400 border-yellow-400 text-black shadow-xl scale-105' 
                    : (theme === 'dark' ? 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:border-zinc-700' : 'bg-white border-gray-100 text-gray-400 hover:border-gray-200 shadow-sm')
                }`}
              >
                <cat.icon size={28} className="mb-3" />
                <span className="text-[10px] font-black uppercase tracking-widest">{cat.label}</span>
              </button>
            ))}
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
            {filteredProducts.map(product => (
              <div 
                key={product.id} 
                className={`group rounded-[48px] overflow-hidden border-2 transition-all hover:shadow-2xl hover:-translate-y-1 ${
                  theme === 'dark' ? 'bg-zinc-900 border-zinc-800 hover:border-zinc-700' : 'bg-white border-gray-100 hover:border-gray-200'
                }`}
              >
                <div className="relative aspect-[4/3] overflow-hidden cursor-pointer" onClick={() => setSelectedProduct(product)}>
                  <img src={product.image} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
                  <button 
                    onClick={(e) => { e.stopPropagation(); onToggleFavorite(product.id); }}
                    className={`absolute top-6 right-6 p-4 rounded-3xl transition-all active:scale-90 shadow-xl ${
                      product.isFavorite ? 'bg-red-500 text-white' : 'bg-white/80 backdrop-blur-md text-gray-900 hover:bg-white'
                    }`}
                  >
                    <Heart size={20} fill={product.isFavorite ? "currentColor" : "none"} />
                  </button>
                  <div className="absolute bottom-6 left-6 translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all">
                    <span className="bg-yellow-400 text-black px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-xl">
                      {t.details}
                    </span>
                  </div>
                </div>
                <div className="p-8">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h3 className={`font-black text-xl uppercase tracking-tighter mb-1 transition-colors ${theme === 'dark' ? 'text-white' : 'text-gray-900'}`}>{product.name[lang]}</h3>
                      <div className="flex items-center gap-2">
                        <div className="flex text-yellow-400"><Star size={14} fill="currentColor" /></div>
                        <span className="text-[11px] font-black">{product.rating}</span>
                        <span className="text-gray-400 font-bold text-[10px] uppercase">({product.totalReviews} {t.reviews})</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-end justify-between">
                    <div>
                      <div className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">{t.retail}</div>
                      <div className={`text-2xl font-black transition-colors ${theme === 'dark' ? 'text-white' : 'text-gray-900'}`}>{product.priceRetail.toLocaleString()} <span className="text-xs">UZS</span></div>
                    </div>
                    <button 
                      onClick={() => setSelectedProduct(product)}
                      className={`p-5 rounded-[28px] transition-all active:scale-90 shadow-lg ${theme === 'dark' ? 'bg-white text-black hover:bg-zinc-200' : 'bg-black text-white hover:bg-zinc-800'}`}
                    >
                      <Zap size={24} />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </>
      )}

      {view === 'chat' && renderChatView()}

      {view === 'fav_list' && (
        <div className="text-center py-20 animate-in fade-in zoom-in duration-300">
          <Heart size={80} className="mx-auto text-gray-200 mb-6" />
          <h2 className="text-2xl font-black uppercase tracking-tighter mb-2">{t.favorites}</h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest">{t.emptyCart}</p>
        </div>
      )}

      {view === 'cart' && (
        <div className="max-w-3xl mx-auto space-y-6">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-3xl font-black uppercase tracking-tighter">{t.yourOrder}</h2>
            <div className="bg-yellow-400 text-black px-4 py-2 rounded-2xl font-black text-xs uppercase shadow-xl">
              {cart.length} {lang === 'ru' ? 'поз.' : 'dona'}
            </div>
          </div>

          {cart.length > 0 ? (
            <>
              {cart.map(item => (
