                  </div>
                  <div className="text-right">
                    <div className={`text-2xl font-black transition-colors duration-300 ${theme === 'dark' ? 'text-white' : 'text-gray-900'}`}>
                      {Math.round((isWholesale ? product.priceWholesale : product.priceRetail) * (qty || 1)).toLocaleString()}
                    </div>
                    <div className="text-[9px] font-black text-gray-400 uppercase tracking-widest">UZS TOTAL</div>
