              <div>
                <h3 className="font-black text-sm uppercase tracking-tight">{currentChat?.name}</h3>
                <div className="flex items-center gap-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse" />
                  <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{t.supportOnline}</span>
                </div>
              </div>
            </div>
            <div className={`p-3 rounded-2xl ${theme === 'dark' ? 'bg-zinc-800' : 'bg-white shadow-sm'}`}>
              {currentChat?.type === 'support' ? <Headset size={20} className="text-yellow-400" /> : <Store size={20} className="text-blue-500" />}
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-4 scrollbar-hide">
            {messages.map((msg) => (
              <div key={msg.id} className={`flex ${msg.sender === 'me' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[85%] p-5 rounded-[32px] shadow-sm relative ${
                  msg.sender === 'me' 
                    ? 'bg-yellow-400 text-black rounded-tr-none' 
                    : (theme === 'dark' ? 'bg-zinc-800 text-white rounded-tl-none border border-zinc-700' : 'bg-gray-100 text-black rounded-tl-none')
