                  <p className="text-[13px] font-bold leading-relaxed">{msg.text}</p>
                  <div className={`text-[8px] mt-2 flex items-center gap-1 font-black uppercase opacity-60`}>
                    {msg.time}
                    {msg.sender === 'me' && <CheckCheck size={10} />}
                  </div>
                </div>
              </div>
            ))}
            <div ref={chatEndRef} />
          </div>

          <div className={`p-6 border-t-2 flex items-center gap-4 ${theme === 'dark' ? 'border-zinc-800 bg-zinc-900' : 'border-gray-50 bg-white'}`}>
