                theme === 'dark' ? 'border-zinc-800 focus:border-yellow-400 text-white' : 'border-gray-100 focus:border-yellow-400'
              }`}
            />
            <button 
              onClick={handleSendMessage}
              className="p-4 bg-yellow-400 text-black rounded-2xl active:scale-95 transition-all shadow-xl hover:shadow-yellow-400/20"
            >
              <Send size={20} />
            </button>
          </div>
        </div>
      );
    }

    return (
      <div className="space-y-8 animate-in fade-in slide-in-from-bottom-10 duration-500">
        <div className={`flex p-1.5 rounded-[32px] transition-colors duration-300 ${theme === 'dark' ? 'bg-zinc-900 border-2 border-zinc-800' : 'bg-gray-100 border-2 border-gray-50'}`}>
          <button 
            onClick={() => setActiveChatTab('support')}
            className={`flex-1 flex items-center justify-center gap-3 py-5 rounded-[24px] text-[11px] font-black uppercase tracking-widest transition-all ${
