                  </div>
                </div>
                <div className="p-10">
                  <div className="flex justify-between items-start mb-6">
                    <div>
                      <h3 className={`font-black text-2xl uppercase tracking-tighter mb-2 transition-colors duration-500 ${theme === 'dark' ? 'text-white' : 'text-gray-900'}`}>{product.name[lang]}</h3>
                      <div className="flex items-center gap-3">
                        <div className="flex text-yellow-400"><Star size={16} fill="currentColor" /></div>
                        <span className="text-xs font-black tracking-widest">{product.rating}</span>
                        <div className="w-1 h-1 rounded-full bg-gray-300" />
                        <span className="text-gray-400 font-bold text-[10px] uppercase tracking-widest">{product.totalReviews} {t.reviews}</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-end justify-between pt-6 border-t border-dashed border-gray-200 dark:border-zinc-800">
                    <div>
                      <div className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-2">{t.retail}</div>
                      <div className={`text-3xl font-black transition-colors duration-500 ${theme === 'dark' ? 'text-white' : 'text-gray-900'}`}>
                        {product.priceRetail.toLocaleString()} <span className="text-xs opacity-50 ml-1 font-bold">UZS</span>
                      </div>
                    </div>
                    <div className={`p-6 rounded-[32px] transition-all duration-500 shadow-xl group-hover:rotate-12 ${theme === 'dark' ? 'bg-white text-black' : 'bg-black text-white shadow-black/20'}`}>
                      <Zap size={28} />
                    </div>
                  </div>
