          <div className="w-32 h-32 bg-gray-100 dark:bg-zinc-900 rounded-[48px] flex items-center justify-center mx-auto mb-10 shadow-inner">
            <Heart size={48} className="text-gray-300 dark:text-zinc-800" />
          </div>
          <h2 className="text-4xl font-black uppercase tracking-tighter mb-4">{t.favorites}</h2>
          <p className="text-gray-400 font-bold uppercase text-[12px] tracking-[0.3em]">{t.emptyCart}</p>
