                        {item.isWholesale ? t.wholesale : t.retail}
                      </span>
                      <span className="text-xs text-gray-400 font-black tracking-widest">UNIT: {item.attributes[0]?.value}</span>
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="text-3xl font-black leading-none mb-1">{(item.quantity * (item.isWholesale ? item.priceWholesale : item.priceRetail)).toLocaleString()}</div>
                    <div className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">UZS TOTAL</div>
                  </div>
                </div>
              ))}
              <div className={`mt-12 p-12 rounded-[72px] transition-all shadow-3xl ${theme === 'dark' ? 'bg-zinc-900 border-2 border-zinc-800' : 'bg-black text-white shadow-black/40'}`}>
                <div className="flex justify-between items-center mb-10">
                  <div>
                    <div className="text-[11px] font-black opacity-50 uppercase tracking-[0.4em] mb-4">{t.total.toUpperCase()}</div>
                    <div className="text-6xl font-black tracking-tighter flex items-end gap-3">
                      {cart.reduce((acc, item) => acc + (item.quantity * (item.isWholesale ? item.priceWholesale : item.priceRetail)), 0).toLocaleString()}
