        </div>
      )}

      {view === 'profile' && (
        <div className="max-w-2xl mx-auto space-y-10 animate-in fade-in slide-in-from-right-10 duration-700">
          <div className="text-center">
            <div className="w-48 h-48 bg-yellow-400 rounded-[64px] mx-auto mb-10 flex items-center justify-center shadow-3xl relative rotate-3 group">
              <User size={96} className="text-black transition-transform duration-500 group-hover:scale-110" />
              <div className="absolute -bottom-4 -right-4 bg-green-500 w-16 h-16 rounded-[24px] border-[8px] border-white dark:border-zinc-950 flex items-center justify-center shadow-2xl">
